parameters.jsCode:
const raw = $input.first().json.stdout || '';
const exitMatch = raw.match(/EXIT_CODE:(\d+)/);
const exitCode = exitMatch ? parseInt(exitMatch[1]) : 99;

let report = {};
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  if (jsonMatch) report = JSON.parse(jsonMatch[0]);
} catch(e) {
  report = { error: e.message };
}

const summary = report.summary || {};
return [{
  json: {
    exitCode,
    critical: summary.critical || 0,
    high: summary.high || 0,
    totalFindings: summary.total_findings || 0,
    filesScanned: summary.total_files_scanned || 0,
    compliantScripts: summary.compliant_scripts || 0,
    nonCompliantScripts: summary.non_compliant_scripts || 0,
    findings: report.findings || [],
    compliance: report.compliance || [],
    scanTimestamp: report.scan_timestamp,
    gitBranch: report.git_branch,
    gitSha: report.git_sha
  }
}];

